sheet.mermaid-diagram:
flowchart TD
%% Nodes A([Content Update Detected]) B[Retrieve Latest Content] C[Parse and Clean HTML] D[Semantic Chunking] E[Generate Embeddings] F[Update Vector Database] G([Synchronization Complete])
%% Flow A --> B B --> C C --> D D --> E E --> F F --> G
%% Styling classDef process fill:#1c5d8c,stroke:#0d2b45,stroke-width:2px,color:#ffffff; classDef highlight fill:#fdf6ea,stroke:#e8a33d,stroke-width:2px,color:#b5791c; classDef startend fill:#0d2b45,stroke:#e8a33d,stroke-width:3px,color:#ffffff;
class A,G startend; class B,C,D process; class E,F highlight; linkStyle default stroke:#0d2b45,stroke-width:2px;

flowchart TD
%% Nodes A[User Question] B[Embedding] C[Semantic Search] D[(Qdrant)] E[Top Chunks] F[Prompt Builder] G[Gemini] H[Response]
%% Flow A --> B B --> C C --> D D --> E E --> F F --> G G --> H
%% Styling classDef process fill:#1c5d8c,stroke:#0d2b45,stroke-width:2px,color:#ffffff; classDef highlight fill:#fdf6ea,stroke:#e8a33d,stroke-width:2px,color:#b5791c; classDef startend fill:#0d2b45,stroke:#e8a33d,stroke-width:3px,color:#ffffff;
class A,H startend; class B,C,E,F process; class D,G highlight; linkStyle default stroke:#0d2b45,stroke-width:2px;
